6 #ifndef MODEL_H
7 #define MODEL_H
8 
9 #include "Foundation/Util/Types.h"
10 #include "Rendering/Geometry/Drawable.h"
11 #include "Foundation/Math/Math3D.h"
12 #include "Rendering/Geometry/ModelPart.h"
13 #include "Scene/Camera.h"
14 #include "Rendering/Lighting/ShadowRenderer.h"
15 
16 #include <string>
17 #include <vector>
18 #include <glad/glad.h>
19 
21 struct Model : public IDrawable{
22     private:
23         Math3D::Transform modelTransform;
24         std::vector<std::shared_ptr<ModelPart>> modelParts;
25         bool enableBackfaceCulling = true;
26         std::string sourceAssetRef;
27         bool sourceForceSmoothNormals = false;
28     public:
29 
33         Model() = default;
34 
40         Model& addPart(std::shared_ptr<ModelPart> part){
41             modelParts.push_back(part);
42             return *this;
43         }
44 
49         const std::vector<std::shared_ptr<ModelPart>>& getParts() const {
50             return modelParts;
51         }
52 
57         Math3D::Transform& transform(){
58             return modelTransform;
59         }
60 
65         void setBackfaceCulling(bool enabled){
66             enableBackfaceCulling = enabled;
67         }
68 
73         bool isBackfaceCullingEnabled() const {
74             return enableBackfaceCulling;
75         }
76 
81         void setSourceAssetRef(const std::string& sourceRef){
82             sourceAssetRef = sourceRef;
83         }
84 
89         const std::string& getSourceAssetRef() const{
90             return sourceAssetRef;
91         }
92 
97         void setSourceForceSmoothNormals(bool enabled){
98             sourceForceSmoothNormals = enabled;
99         }
100 
105         bool getSourceForceSmoothNormals() const{
106             return sourceForceSmoothNormals;
107         }
108 
115         void draw(
116             const Math3D::Mat4& parent = Math3D::Mat4(),
117             const Math3D::Mat4& view = Math3D::Mat4(),
118             const Math3D::Mat4& projection = Math3D::Mat4()
119         ) override {
120 
121             Math3D::Mat4 global = parent * transform().toMat4();
122 
123             // Enable or disable backface culling for this model
124             if(enableBackfaceCulling){
125                 glEnable(GL_CULL_FACE);
126                 glCullFace(GL_BACK);
127             }else{
128                 glDisable(GL_CULL_FACE);
129             }
130 
131             for(auto part : modelParts){
132                 if(part && part->visible){
133                     part->draw(global, view, projection);
134                 }
135             }
136 
137             // Restore default culling state
138             glEnable(GL_CULL_FACE);
139             glCullFace(GL_BACK);
140         };
141 
146         void drawShadows(const Math3D::Mat4& parent = Math3D::Mat4()){
147             Math3D::Mat4 global = parent * transform().toMat4();
148             for(auto part : modelParts){
149                 if(part && part->visible && part->mesh){
150                     Math3D::Mat4 worldMatrix = global * part->localTransform.toMat4();
151                     ShadowRenderer::RenderShadows(part->mesh, worldMatrix, part->material);
152                 }
153             }
154         }
155 
161         void draw(PCamera cam, Nullable<Math3D::Transform> parentTransform = nullptr){
162             if(!cam) return;
163 
164             auto parentMatrix = parentTransform.hasValue() 
165                 ? parentTransform->toMat4()
166                 : Math3D::Mat4(1.0f);
167 
168             this->draw(
169                 parentMatrix,
170                 cam->getViewMatrix(),
171                 cam->getProjectionMatrix()
172             );
173         }
174 
179         static std::shared_ptr<Model> Create(){
180             return std::make_shared<Model>();
181         }
182 };
183 
184 typedef std::shared_ptr<Model> PModel;
185 
186 #endif // MODEL_H
